        self.session = URLSession(configuration: .default)
    }
    
    func fetchData(completion: @escaping (Data?, Error?) -> Void) {
        var request = URLRequest(url: environment.baseURL.appendingPathComponent("data"))
        request.httpMethod = "GET"
        
        let task = session.dataTask(with: request) { data, response, error in
            completion(data, error)
        }
        
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Bool, Error?) -> Void) {
        var request = URLRequest(url: environment.baseURL.appendingPathComponent("auth"))
        request.httpMethod = "POST"
        request.httpBody = try? JSONEncoder().encode(["username": username, "password": password])
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(false, error)
            } else if let data = data {
                // Handle authentication response
                completion(true, nil)
            }
        }
        
        task.resume()
    }
    
    func pinCertificates() -> Bool {
        guard let url = environment.baseURL else { return false }
        guard let certificates = Bundle.main.paths(forResourcesOfTypes: ["cer"], inDirectory: nil).map { try? Data(contentsOf: URL(fileURLWithPath: $0)) } else { return false }
        
        var trust: SecTrust?
        if let session = session.configuration.urlSessionConfiguration as? URLSessionConfiguration {
            session.httpAdditionalHeaders = ["Accept": "application/json"]
        }
        
        guard let urlSessionTask = session.dataTask(with: url) { data, response, error in
            guard let response = response as? HTTPURLResponse else { return }
            guard let serverTrust = response.securityTrust else { return }
            
            SecTrustSetAnchorCertificates(serverTrust, certificates as CFArray)
            SecTrustEvaluate(serverTrust, &trust)
